  .slide-7 { background: var(--bg-dark); }
  .slide-7 .slide-label { color: var(--accent-green); }
  .slide-7 .pillar-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 24px;
    margin-bottom: 28px;
  }
  .slide-7 .pillar-card {
    background: var(--bg-card);
    border-radius: 16px;
    padding: 32px;
    border-top: 3px solid;
  }
  .slide-7 .pillar-card .p-icon { font-size: 32px; margin-bottom: 10px; }
  .slide-7 .pillar-card h3 {
    font-size: 24px;
    font-weight: 800;
    color: var(--text-primary);
    margin-bottom: 10px;
  }
  .slide-7 .pillar-card .p-features {
    font-size: 18px;
    color: var(--text-secondary);
    line-height: 1.7;
    margin-bottom: 14px;
  }
  .slide-7 .pillar-card .p-tagline {
    font-size: 17px;
    font-weight: 600;
    padding-top: 12px;
    border-top: 1px solid var(--border);
    line-height: 1.4;
  }

  .slide-7 .arch-note {
    background: var(--bg-card);
    border-radius: 16px;
    padding: 28px 32px;
    display: flex;
    gap: 32px;
  }
  .slide-7 .arch-item {
    flex: 1;
    min-width: 0;
  }
  .slide-7 .arch-item .arch-label {
    font-size: 18px;
    font-weight: 800;
    letter-spacing: 0.5px;
    margin-bottom: 6px;
  }
  .slide-7 .arch-item .arch-desc {
    font-size: 18px;
    color: var(--text-secondary);
    line-height: 1.5;
  }

  /* ════════════════════════════════════════════════════ */
  /* SLIDE 8 — TAKEAWAY                                 */
  /* ════════════════════════════════════════════════════ */
  .slide-8 {
    background: linear-gradient(160deg, #0f172a 0%, #1a2332 50%, #0f172a 100%);
  }
  .slide-8 .slide-label { color: var(--accent-amber); }
